package cn.zpl;

import java.util.HashMap;
import java.util.Map;

public class JsDecoder {

    private static final String BASE_CHARS = "0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ+/";

    // 模拟JavaScript的eval函数（在Java中需要根据实际需求处理）
    public static String decodeJs(String encodedStr, int fromBase, int toBase) {
        String fromChars = BASE_CHARS.substring(0, fromBase);
        String toChars = BASE_CHARS.substring(0, toBase);

        // 反转字符串（模拟JavaScript的reverse()）
        StringBuilder reversed = new StringBuilder(encodedStr).reverse();

        // 转换为十进制
        long decimalValue = 0;
        for (int i = 0; i < reversed.length(); i++) {
            char c = reversed.charAt(i);
            int index = fromChars.indexOf(c);
            if (index != -1) {
                decimalValue += index * Math.pow(fromBase, i);
            }
        }

        // 转换为目标进制
        StringBuilder result = new StringBuilder();
        long num = decimalValue;

        do {
            result.insert(0, toChars.charAt((int) (num % toBase)));
            num = (num - (num % toBase)) / toBase;
        } while (num > 0);

        return result.length() > 0 ? result.toString() : "0";
    }

    // 主解码函数
    public static String decodeFunction(String h, String u, String n, int t, int e, int r) {
        StringBuilder result = new StringBuilder();

        for (int i = 0; i < h.length(); i++) {
            StringBuilder s = new StringBuilder();

            // 分割字符串直到遇到分隔符
            while (i < h.length() && h.charAt(i) != n.charAt(e)) {
                s.append(h.charAt(i));
                i++;
            }

            // 字符替换
            for (int j = 0; j < n.length(); j++) {
                s = new StringBuilder(s.toString().replace(
                        String.valueOf(n.charAt(j)),
                        String.valueOf(j)
                ));
            }

            // 转换为字符
            long charCode = Long.parseLong(
                    decodeJs(s.toString(), e, 10)
            ) - t;

            result.append((char) charCode);
        }

        // URL解码（模拟JavaScript的decodeURIComponent）
        try {
            return java.net.URLDecoder.decode(result.toString(), "UTF-8");
        } catch (Exception ex) {
            return result.toString();
        }
    }

    public static void main(String[] args) {
        // 示例用法
        // 示例用法 - 这里只显示部分编码内容作为示意
        String encodedData = ""; // 实际使用时需要完整的编码字符串

        String result = decodeFunction(
                encodedData,
                "58",
                "mBDfQhtcU",
                20, 5, 39
        );
        System.out.println(result);
    }
}